/*
* Show or hide War Type Coverage field with War and Product
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product field has a Hull options selected
    if (this.YQP_PRODUCT_HULL_VALIDATE == "YES") {
        //War is YES
        if (this.YQP_WAR == "YES") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Limit Personal Effects field with Personal Effects and Product
* is Hull or Hull_PI
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product field is HULL or HULL_PI
    if (this.YQP_PERSONAL_EFFECTS_VALIDATION == "YES") {
        //Personal Effects is YES
        if (this.YQP_PERSONAL_EFFECTS == "YES") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Limit Medical Payments field with Medical Payments and
* Product as PI option selected
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product option has PI
    if (this.YQP_PI_VALIDATION == "YES") {
        //Medical Payments is YES
        if (this.YQP_MEDICAL_PAYMENTS == "YES") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Tenders record list with Tenders and Product
* with an option without Excluded losses
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product has an option without Excluded losses
    if (this.YQP_TENDERS_SHOW == "YES") {
        //Tenders is YES
        if (this.YQP_TENDERS == "YES") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Special Area field with Product with an option with HULL and
* Special area is YES
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product field has an option with HULL
    if (this.YQP_PRODUCT_HULL_VALIDATE == "YES") {
        //Special Area is YES
        if (this.YQP_SPECIAL_AREA == "YES") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Special Percentage Deductible field with Product with an option
* with Hull and Special Area is YES and Special deductible is Percentage
* by Ana Castillo
*/
//It is Submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Product has an option with HUll
    if (this.YQP_PRODUCT_HULL_VALIDATE == "YES") {
        //Special Area is YES and Show special deductible is Percentage
        if (this.YQP_SPECIAL_AREA == "YES" && 
            this.YQP_SHOW_SPECIAL_DEDUCTIBLE == "PER") {
            return "YES";
        } else {
            return "NO";
        }
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Calc Show request error
* by Helen Callisaya
*/
//Validate if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

/*
* Show or hide Contamination Limit field with Contamination
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Contamination is YES
    if (this.YQP_CONTAMINATION == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Damage Limit field with Damage
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Damage is YES
    if (this.YQP_DAMAGE == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Owners Uninsured Vessel Limit field with Owners Uninsured Vessel
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Owners Uninsured Vessel is YES
    if (this.YQP_OWNERS_UNINSURED_VESSEL == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Towing Assistance Limit field with Towing Assistance
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Towing Assistance is YES
    if (this.YQP_TOWING_ASSISTANCE == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Show or hide Submit field with Tenders record list and Product 
* without Excluded losses, Contamination Clause, Clause Damage to the Environment and
* Owners, Operators of an Uninsured Vessel and Water-Skiing Coverage
*
* by Ana Castillo
* modified by Helen Callisaya
*/
//Defines an object to store values
var submitVariables = new Object();
submitVariables['YQP_CONTAMINATION_LIMIT_SHOW'] = "NO";
submitVariables['YQP_DAMAGE_LIMIT_SHOW'] = "NO";
submitVariables['YQP_OWNERS_UNINSURED_VESSEL_LIMIT_SHOW'] = "NO";
submitVariables['YQP_WATER_SKIING_LIMIT_SHOW'] = "NO";
submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
submitVariables['YQP_TENDER_TOWED_YES'] = "YES";
submitVariables['YQP_VALIDATE_PERIOD'] = "YES";
//Add 18 months
var periodMaximum = moment(this.YQP_PERIOD_FROM, "YYYY-MM-DD");
var periodMaximum = moment(periodMaximum).add('months', 18).format('YYYY-MM-DD');
submitVariables['YQP_PERIOD_MAXIMUM'] = periodMaximum;
//Validate Period Maximum
if (this.YQP_PERIOD_FROM != "" && this.YQP_PERIOD_FROM != null && this.YQP_PERIOD_TO != "" && this.YQP_PERIOD_TO != null) {
    var periodTo = moment(this.YQP_PERIOD_TO, "YYYY-MM-DD");
    if (moment(periodTo).isSameOrBefore(periodMaximum) != true) {
        submitVariables['YQP_VALIDATE_PERIOD'] = "NO";        
    }
}

//set tender limit at 50% of the sum insured
submitVariables['YQP_TENDER_LIMIT_50'] = this.YQP_SUM_INSURED_VESSEL / 2;
//Validation YQP_CONTAMINATION_LIMIT
if (this.YQP_CONTAMINATION == 'YES') {
    if (this.YQP_CONTAMINATION_LIMIT > this.YQP_LIMIT_PI) {
        submitVariables['YQP_CONTAMINATION_LIMIT_SHOW'] = "YES";
    }
}
//Validation YQP_DAMAGE_LIMIT
if (this.YQP_DAMAGE == 'YES') {
    if (this.YQP_DAMAGE_LIMIT > this.YQP_LIMIT_PI) {
        submitVariables['YQP_DAMAGE_LIMIT_SHOW'] = "YES";
    }
}
//Validation YQP_OWNERS_UNINSURED_VESSEL_LIMIT
if (this.YQP_OWNERS_UNINSURED_VESSEL == 'YES') {
    if (this.YQP_LIMIT_PI <= 2000000) {
        submitVariables['YQP_OWNERS_UNINSURED_VESSEL_MAX'] = this.YQP_LIMIT_PI;
    } else {
        submitVariables['YQP_OWNERS_UNINSURED_VESSEL_MAX'] = 2000000;
    }
    if (this.YQP_OWNERS_UNINSURED_VESSEL_LIMIT > submitVariables['YQP_OWNERS_UNINSURED_VESSEL_MAX']) {
        submitVariables['YQP_OWNERS_UNINSURED_VESSEL_LIMIT_SHOW'] = "YES";
    }
}
//Validation YQP_WATER_SKIING_LIMIT
if (this.YQP_WATER_SKIING == 'YES') {
    if (this.YQP_LIMIT_PI <= 1000000) {
        submitVariables['YQP_WATER_SKIING_MAX'] = this.YQP_LIMIT_PI;
    } else {
        submitVariables['YQP_WATER_SKIING_MAX'] = 2000000;
    }
    if (this.YQP_WATER_SKIING_LIMIT > submitVariables['YQP_WATER_SKIING_MAX']) {
        submitVariables['YQP_WATER_SKIING_LIMIT_SHOW'] = "YES";
    }
}
//Product has an option without Excluded losses
var messageTender = '';
var yesTender = 0;
if (this.YQP_TENDERS_SHOW == "YES") {
    //Tenders is YES
    if (this.YQP_TENDERS == "YES") {
        //Tenders record list has no options
        if (this.YQP_TENDERS_INFORMATION == null) {
            submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
            submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "YES";
        } else {
            //Validate Tenders limit to see if there are rows
            let tendersLength = this.YQP_TENDERS_INFORMATION.length;
            if (tendersLength == 0) {
                submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
                submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "YES";
            } else {
                //Set Flag to validate Reinsurer Information
                let flagTender = 0;
                var sum = 0;
                for (let t = 0; t < tendersLength; t++) {
                    //validar que solo este marcado una posicion
                    if (this.YQP_TENDERS_INFORMATION[t]['YQP_TENDERS_TOWED'] == "YES") {
                        yesTender = yesTender + 1;
                    }
                    //Validate if fields are differents
                    if (this.YQP_TENDERS_INFORMATION[t]['YQP_TENDERS_LIMIT'] != "" && 
                        this.YQP_TENDERS_INFORMATION[t]['YQP_TENDERS_LIMIT'] != null &&
                        this.YQP_TENDERS_INFORMATION[t]['YQP_TENDERS_LIMIT'] <= submitVariables['YQP_TENDER_LIMIT_50']) {
                        flagTender = 1;
                    } else {
                        messageTender += [t+1] + ", ";
                    }
                }
                if( yesTender > 1) {
                    submitVariables['YQP_TENDER_TOWED_YES'] = "NO";
                }
                if (messageTender != '') {
                    submitVariables['YQP_TENDER_LIMIT_SHOW'] = "YES";
                    submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "YES";
                } else {
                    submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
                    submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "NO";
                }          
                submitVariables['YQP_TENDER_LIMIT_MESSAGE'] = messageTender.substring(0, messageTender.length - 2);
            }
        }
    } else {
        submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
        submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "NO";
    }
} else {
    submitVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
    submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] = "NO";
}

//--------------------------------------
if (submitVariables['YQP_CONTAMINATION_LIMIT_SHOW'] == "NO" && 
    submitVariables['YQP_DAMAGE_LIMIT_SHOW'] == "NO" && 
    submitVariables['YQP_OWNERS_UNINSURED_VESSEL_LIMIT_SHOW'] == "NO" && 
    submitVariables['YQP_TENDER_LIMIT_VALIDATE_SHOW'] == "NO" && 
    submitVariables['YQP_WATER_SKIING_LIMIT_SHOW'] == "NO" &&
    submitVariables['YQP_TENDER_TOWED_YES'] == "YES" &&
    submitVariables['YQP_VALIDATE_PERIOD'] == "YES") {
    submitVariables['YQP_SUBMIT'] = "YES";
} else {
    submitVariables['YQP_SUBMIT'] = "NO";
}
return submitVariables;

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Show or hide Water Skiing Limit field with Water Skiing
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Water Skiing is YES
    if (this.YQP_WATER_SKIING == "YES") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Shows message when the tender limit exceeds 50% of the sum insured
* by Helen
*/
//Create object
var validateVariables = new Object;
validateVariables['YQP_TENDER_LIMIT_50'] = this.YQP_SUM_INSURED_VESSEL_GRID / 2;
//Valid tender limit
if (this.YQP_TENDERS_LIMIT <= validateVariables['YQP_TENDER_LIMIT_50']) {
    validateVariables['YQP_TENDER_LIMIT_SHOW'] = "NO";
} else {
    validateVariables['YQP_TENDER_LIMIT_SHOW'] = "YES";
}
return validateVariables;

/*
* Required field visible
* by Helen Callisaya
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Machinery field has a Hull options selected
    if (this.PM_OPEN_OPTION_MACHINERY_VALIDATE == "YES") {
	    return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Required field Show Deductible
* by Helen Callisaya
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Machinery field has a Hull options selected
    if (this.YQP_PRODUCT_HULL_VALIDATE == "YES") {
	    return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

/*
* Calc Check if the variable exists
* by Helen Callisaya
*/
if (this.END_CASE_CAN_CONTINUE) {
    return 'YES';
} else {
    return 'NO';
}

